#!/usr/bin/env node
/**
 * set-properties.js
 *
 * Reads credentials from .env and writes a temporary Apps Script file
 * (src/_SetupProperties.js) that contains a one-shot function to push
 * all values into Script Properties on Google's servers.
 *
 * Workflow:
 *   1.  npm run set-properties   ← this script (generates the GAS file)
 *   2.  clasp push               ← upload the generated file
 *   3.  Open the Apps Script editor → Run → setScriptProperties
 *   4.  npm run clean-properties ← removes the generated file
 *   5.  clasp push               ← clean deploy without the bootstrap file
 */

'use strict';

const fs   = require('fs');
const path = require('path');

const ROOT    = path.resolve(__dirname, '..');
const OUT     = path.join(ROOT, 'src', '_SetupProperties.js');
const ENV_FILE = path.join(ROOT, '.env');

// ── Parse .env ──────────────────────────────────────────────────────────────
function loadEnv(filePath) {
  if (!fs.existsSync(filePath)) {
    console.error('Error: .env file not found at', filePath);
    console.error('Copy .env.example to .env and fill in your values.');
    process.exit(1);
  }
  const lines = fs.readFileSync(filePath, 'utf8').split('\n');
  const env   = {};
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) continue;
    const idx = trimmed.indexOf('=');
    if (idx === -1) continue;
    env[trimmed.slice(0, idx).trim()] = trimmed.slice(idx + 1).trim();
  }
  return env;
}

const env = loadEnv(ENV_FILE);

const required = ['GOOGLE_SHEET_ID', 'ADMIN_EMAILS'];
const missing  = required.filter(k => !env[k]);
if (missing.length) {
  console.error('Error: the following keys are missing or empty in .env:');
  missing.forEach(k => console.error('  ' + k));
  process.exit(1);
}

// ── Escape a string value to be safe inside a JS string literal ─────────────
function esc(value) {
  return value.replace(/\\/g, '\\\\').replace(/'/g, "\\'");
}

// ── Generate the GAS bootstrap file ─────────────────────────────────────────
const properties = {
  GOOGLE_SHEET_ID: env['GOOGLE_SHEET_ID'],
  ADMIN_EMAILS:    env['ADMIN_EMAILS'],
};
if (env['GCP_PROJECT_NUMBER']) {
  properties['GCP_PROJECT_NUMBER'] = env['GCP_PROJECT_NUMBER'];
}

const propLines = Object.entries(properties)
  .map(([k, v]) => `  props.setProperty('${esc(k)}', '${esc(v)}');`)
  .join('\n');

const code = `/**
 * _SetupProperties.js — AUTO-GENERATED by scripts/set-properties.js
 *
 * THIS FILE IS GITIGNORED. DO NOT COMMIT.
 *
 * Run this function ONCE from the Apps Script editor:
 *   Editor → Run → setScriptProperties
 *
 * Then run: npm run clean-properties && clasp push
 */

/* global PropertiesService, Logger */

function setScriptProperties() {
  var props = PropertiesService.getScriptProperties();
${propLines}
  Logger.log('Script Properties set successfully.');
}
`;

fs.writeFileSync(OUT, code, 'utf8');

console.log('');
console.log('✓ Generated: src/_SetupProperties.js');
console.log('');
console.log('Next steps:');
console.log('  1.  clasp push');
console.log('  2.  Open the Apps Script editor (https://script.google.com)');
console.log('      → Select setScriptProperties from the function dropdown');
console.log('      → Click Run');
console.log('  3.  npm run clean-properties');
console.log('  4.  clasp push');
console.log('');
